<h1>Admin → Products</h1><nav class="tabs"><?php foreach(['pending_review'=>'Pending Review','approved'=>'Approved','rejected'=>'Rejected','disabled'=>'Disabled'] as $key=>$label):?><a class="<?=($status??'pending_review')===$key?'active':''?>" href="/admin/products?status=<?=$key?>"><?=H::e($label)?></a><?php endforeach;?></nav><table><tr><th>Product</th><th>Designer</th><th>Category</th><th>Status</th><th>Actions</th></tr><?php foreach($products as $p):?><tr><td><a href="/admin/products/<?=$p['id']?>"><?=H::e($p['title'])?></a></td><td><?=H::e($p['display_name'])?></td><td><?=H::e($p['category_name']??'Uncategorized')?></td><td><?=H::e(ucwords(str_replace('_',' ',$p['status'])))?></td><td><a href="/admin/products/<?=$p['id']?>">Review</a><form method="post"><input type="hidden" name="_csrf" value="<?=H::csrf()?>"><input type="hidden" name="id" value="<?=$p['id']?>"><input name="reason" placeholder="Rejection Reason"><button name="action" value="approve">Approve</button><button name="action" value="reject">Reject</button><button name="action" value="disable">Disable</button></form></td></tr><?php endforeach;?></table>
